}) {
  const [hasOpenedTerminal, setHasOpenedTerminal] = useState(
    props.view === 'terminal'
  );
  const isKanbanActive = props.view === 'kanban';
  const shouldRenderTerminal = hasOpenedTerminal || props.view === 'terminal';

  useEffect(() => {
    if (props.view !== 'terminal') {
