func (p *WorkspaceProvider) attachCommand(ctx context.Context, runtimeKind string, runtimeTarget string) ([]string, bool) {
	if runtimeTarget == "" || runtime.GOOS == "windows" {
		return nil, false
	}

	switch runtimeKind {
	case "zellij":
		zellijPath := p.zellijPath()
		if zellijPath == "" || !p.hasZellijSession(ctx, runtimeTarget) {
			return nil, false
		}

		return []string{zellijPath, "attach", runtimeTarget}, true
	case "tmux":
		tmuxPath := p.tmuxPath()
		if tmuxPath == "" || !p.hasTmuxSession(ctx, runtimeTarget) {
			return nil, false
		}

		return tmuxAttachCommand(tmuxPath, runtimeTarget), true
	default:
		return nil, false
	}
}

