		InitialCols: cols,
		InitialRows: rows,
		PipePath:    workerSession.PipePath,
		TerminalKey: workerSession.TerminalKey,
		Title:       workerSession.Title,
		WorkerID:    workerSession.WorkerID,
	})
}

